import React from 'react';
import { Card, CardContent, Box, Typography, Stack } from '@mui/material';
import { LineChart } from '@mui/x-charts';
import { TrendingUp, TrendingDown } from '@mui/icons-material';
import response from './response.json';

interface EnergyUsageData {
  currentUsage: {
    kilowatts: number;
    cost: number;
  };
  dailyCost: {
    total: number;
    currency: string;
  };
  usageTrend: number[];
}

export default function Widget() {
  const data = response.data as EnergyUsageData;
  const { currentUsage, dailyCost, usageTrend } = data;
  const isIncreasing = usageTrend[usageTrend.length - 1] > usageTrend[0];

  return (
    <Card sx={{ width: 'fit-content', minWidth: 320, maxWidth: 400, bgcolor: '#2C2C2C' }} elevation={2}>
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="body2" sx={{ color: '#FFC107', mb: 0.5 }}>
              Current Usage
            </Typography>
            <Typography variant="h4" sx={{ color: '#FFFFFF', fontWeight: 600 }}>
              {currentUsage.kilowatts.toFixed(1)} kW
            </Typography>
            <Stack direction="row" alignItems="center" spacing={0.5} sx={{ mt: 0.5 }}>
              {isIncreasing ? <TrendingUp sx={{ fontSize: 16, color: '#FF5722' }} /> : <TrendingDown sx={{ fontSize: 16, color: '#FF5722' }} />}
              <Typography variant="body2" sx={{ color: '#FFFFFF' }}>
                ${currentUsage.cost.toFixed(2)}
              </Typography>
            </Stack>
          </Box>

          <LineChart
            height={100}
            series={[
              {
                data: usageTrend,
                color: '#FFC107',
                curve: 'natural',
                showMark: false,
              },
            ]}
            xAxis={[{ data: usageTrend.map((_, i) => i), hide: true }]}
            margin={{ top: 10, bottom: 10, left: 10, right: 10 }}
            sx={{
              '& .MuiLineElement-root': {
                strokeWidth: 2,
              },
            }}
          />

          <Box>
            <Typography variant="body2" sx={{ color: '#FFC107', mb: 0.5 }}>
              Daily Cost
            </Typography>
            <Typography variant="h5" sx={{ color: '#FFFFFF', fontWeight: 500 }}>
              {dailyCost.currency} {dailyCost.total.toFixed(2)}
            </Typography>
          </Box>
        </Stack>
      </CardContent>
    </Card>
  );
}
